def countBattleships(board):
    if not board: return 0
    m, n, cnt = len(board), len(board[0]), 0
    for i in range(m):
        for j in range(n):
            if board[i][j] == 'X':
                if (i == 0 or board[i-1][j] == '.') and (j == 0 or board[i][j-1] == '.'): cnt += 1
    return cnt

